import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🧪 尿素價格趨勢與對黃豆期貨影響報告","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/尿素_尿素價格趨勢與黃豆影響報告.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/尿素_尿素價格趨勢與黃豆影響報告.md"}'),h={name:"Deep32Q知識庫/產業洞察/黃豆研究/尿素_尿素價格趨勢與黃豆影響報告.md"};function o(l,t,n,i,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="🧪-尿素價格趨勢與對黃豆期貨影響報告" tabindex="-1">🧪 尿素價格趨勢與對黃豆期貨影響報告 <a class="header-anchor" href="#🧪-尿素價格趨勢與對黃豆期貨影響報告" aria-label="Permalink to &quot;🧪 尿素價格趨勢與對黃豆期貨影響報告&quot;">​</a></h1><p><strong>報告日期：</strong> 2026-04-27 15:45</p><hr><h2 id="一、尿素市場概況" tabindex="-1">一、尿素市場概況 <a class="header-anchor" href="#一、尿素市場概況" aria-label="Permalink to &quot;一、尿素市場概況&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>數值</th></tr></thead><tbody><tr><td>當前尿素價格</td><td>$480-580/噸（FOB）</td></tr><tr><td>近期高點</td><td>~$650/噸（2025 年底）</td></tr><tr><td>歷史高點</td><td>$900+/噸（2022 年俄烏戰爭初期）</td></tr><tr><td>關鍵閾值</td><td><strong>$700/噸</strong>（突破後種植結構變化）</td></tr></tbody></table><hr><h2 id="二、中東戰事影響" tabindex="-1">二、中東戰事影響 <a class="header-anchor" href="#二、中東戰事影響" aria-label="Permalink to &quot;二、中東戰事影響&quot;">​</a></h2><h3 id="_2-1-中東尿素供應地位" tabindex="-1">2.1 中東尿素供應地位 <a class="header-anchor" href="#_2-1-中東尿素供應地位" aria-label="Permalink to &quot;2.1 中東尿素供應地位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>全球產量佔比</th><th>主要出口市場</th></tr></thead><tbody><tr><td>沙烏地阿拉伯</td><td>~8%</td><td>印度、東南亞</td></tr><tr><td>卡達</td><td>~5%</td><td>印度、東南亞</td></tr><tr><td>阿曼</td><td>~3%</td><td>印度、非洲</td></tr><tr><td><strong>合計中東</strong></td><td><strong>~16%</strong></td><td>亞洲為主</td></tr></tbody></table><h3 id="_2-2-荷莫茲海峽風險" tabindex="-1">2.2 荷莫茲海峽風險 <a class="header-anchor" href="#_2-2-荷莫茲海峽風險" aria-label="Permalink to &quot;2.2 荷莫茲海峽風險&quot;">​</a></h3><ul><li><strong>全球 20% 石油運輸</strong>通過荷莫茲海峽</li><li>中東尿素出口<strong>高度依賴海運</strong></li><li>若海峽封鎖 → 中東尿素出口中斷 → 全球供給缺口 <strong>~5-8%</strong></li><li><strong>傳導鏈</strong>：海峽封鎖 → 中東尿素停運 → 全球供給緊縮 → 價格飆漲 → 種植成本↑ → 黃豆供給↓ → 期貨↑</li></ul><h3 id="_2-3-戰事情境分析" tabindex="-1">2.3 戰事情境分析 <a class="header-anchor" href="#_2-3-戰事情境分析" aria-label="Permalink to &quot;2.3 戰事情境分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情景</th><th>機率</th><th>尿素影響</th><th>黃豆影響</th></tr></thead><tbody><tr><td>低度衝突（現狀）</td><td>60%</td><td>+5-10%</td><td>+2-4%</td></tr><tr><td>海峽短暫封鎖</td><td>25%</td><td>+30-50%</td><td>+12-20%</td></tr><tr><td>全面戰爭</td><td>10%</td><td>+80-120%</td><td>+25-40%</td></tr><tr><td>停火協議</td><td>5%</td><td>-10-15%</td><td>-3-5%</td></tr></tbody></table><hr><h2 id="三、全球供應鏈與貿易戰" tabindex="-1">三、全球供應鏈與貿易戰 <a class="header-anchor" href="#三、全球供應鏈與貿易戰" aria-label="Permalink to &quot;三、全球供應鏈與貿易戰&quot;">​</a></h2><h3 id="_3-1-主要生產國" tabindex="-1">3.1 主要生產國 <a class="header-anchor" href="#_3-1-主要生產國" aria-label="Permalink to &quot;3.1 主要生產國&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>產量（M噸）</th><th>出口限制</th></tr></thead><tbody><tr><td>中國</td><td>~65</td><td>出口關稅+配額</td></tr><tr><td>俄羅斯</td><td>~25</td><td>制裁影響出口</td></tr><tr><td>印度</td><td>~30</td><td>出口禁令（國內優先）</td></tr><tr><td>中東</td><td>~20</td><td>無限制（但海運風險）</td></tr><tr><td>美國</td><td>~15</td><td>無限制</td></tr></tbody></table><h3 id="_3-2-貿易戰對尿素的影響" tabindex="-1">3.2 貿易戰對尿素的影響 <a class="header-anchor" href="#_3-2-貿易戰對尿素的影響" aria-label="Permalink to &quot;3.2 貿易戰對尿素的影響&quot;">​</a></h3><ul><li><strong>中美貿易戰</strong>：不直接影響尿素，但間�影響黃豆需求</li><li><strong>中國出口限制</strong>：中國限制肥料出口保護國內農業 → 全球供給減少</li><li><strong>印度出口禁令</strong>：印度禁止尿素出口 → 進一步收緊全球供給</li><li><strong>俄羅斯制裁</strong>：俄烏戰爭持續 → 俄羅斯肥料出口受限</li></ul><hr><h2 id="四、未來一個月價格展望" tabindex="-1">四、未來一個月價格展望 <a class="header-anchor" href="#四、未來一個月價格展望" aria-label="Permalink to &quot;四、未來一個月價格展望&quot;">​</a></h2><h3 id="_4-1-當前價格區間" tabindex="-1">4.1 當前價格區間 <a class="header-anchor" href="#_4-1-當前價格區間" aria-label="Permalink to &quot;4.1 當前價格區間&quot;">​</a></h3><ul><li><strong>FOB 尿素</strong>：$480-580/噸</li><li><strong>CFR 印度</strong>：$520-620/噸</li><li><strong>FOB 中東</strong>：$460-560/噸</li></ul><h3 id="_4-2-供需展望" tabindex="-1">4.2 供需展望 <a class="header-anchor" href="#_4-2-供需展望" aria-label="Permalink to &quot;4.2 供需展望&quot;">​</a></h3><table tabindex="0"><thead><tr><th>因素</th><th>方向</th><th>影響</th></tr></thead><tbody><tr><td>中東戰事</td><td>可能升級</td><td>偏多</td></tr><tr><td>中國出口限制</td><td>維持</td><td>偏多</td></tr><tr><td>印度進口需求</td><td>穩定</td><td>中性</td></tr><tr><td>北半球種植季</td><td>需求高峰</td><td>偏多</td></tr></tbody></table><h3 id="_4-3-情境分析" tabindex="-1">4.3 情境分析 <a class="header-anchor" href="#_4-3-情境分析" aria-label="Permalink to &quot;4.3 情境分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情景</th><th>價格目標</th><th>機率</th></tr></thead><tbody><tr><td><strong>牛市</strong>（戰事升級）</td><td>$650-800/噸</td><td>25%</td></tr><tr><td><strong>基準</strong>（現狀維持）</td><td>$520-620/噸</td><td>55%</td></tr><tr><td><strong>熊市</strong>（停火+增產）</td><td>$400-480/噸</td><td>20%</td></tr></tbody></table><h3 id="_4-4-關鍵監控指標" tabindex="-1">4.4 關鍵監控指標 <a class="header-anchor" href="#_4-4-關鍵監控指標" aria-label="Permalink to &quot;4.4 關鍵監控指標&quot;">​</a></h3><ul><li>荷莫茲海峽通航狀態</li><li>中國尿素出口政策</li><li>印度進口招標價格</li><li>俄羅斯肥料出口量</li></ul><hr><h2 id="五、對黃豆期貨的綜合影響" tabindex="-1">五、對黃豆期貨的綜合影響 <a class="header-anchor" href="#五、對黃豆期貨的綜合影響" aria-label="Permalink to &quot;五、對黃豆期貨的綜合影響&quot;">​</a></h2><h3 id="_5-1-傳導鏈" tabindex="-1">5.1 傳導鏈 <a class="header-anchor" href="#_5-1-傳導鏈" aria-label="Permalink to &quot;5.1 傳導鏈&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>尿素↑ → 種植成本↑ → 種植意願↓ → 面積↓ → 供給↓ → 黃豆期貨↑</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>       玉米更貴 → 農民轉種黃豆 → 黃豆供給↑ → 價格↓</span></span></code></pre></div><p><strong>關鍵：</strong> 黃豆有固氮能力，肥料漲價對黃豆的衝擊比玉米小。但間接效應（轉種）可能增加黃豆供給。</p><h3 id="_5-2-量化影響" tabindex="-1">5.2 量化影響 <a class="header-anchor" href="#_5-2-量化影響" aria-label="Permalink to &quot;5.2 量化影響&quot;">​</a></h3><table tabindex="0"><thead><tr><th>尿素情景</th><th>對黃豆期貨影響</th></tr></thead><tbody><tr><td>$480-580（當前）</td><td>無額外影響</td></tr><tr><td>$580-700（溫和上漲）</td><td>+2-4%</td></tr><tr><td>$700+（突破閾值）</td><td>+6-10%</td></tr><tr><td>$900+（極端）</td><td>+12-18%</td></tr></tbody></table><h3 id="_5-3-投資建議" tabindex="-1">5.3 投資建議 <a class="header-anchor" href="#_5-3-投資建議" aria-label="Permalink to &quot;5.3 投資建議&quot;">​</a></h3><table tabindex="0"><thead><tr><th>條件</th><th>動作</th></tr></thead><tbody><tr><td>尿素穩定 $500 以下</td><td>黃豆區間操作</td></tr><tr><td>尿素突破 $650</td><td>開始建立黃豆多單</td></tr><tr><td>尿素突破 $700</td><td>加碼黃豆多單</td></tr><tr><td>中東戰事升級</td><td>立即買入黃豆期貨</td></tr></tbody></table><hr><p><em>免責聲明：本報告僅供研究參考，不構成投資建議。</em></p>`,40)])])}const u=d(h,[["render",o]]);export{c as __pageData,u as default};
